SELECT company_name, symbol
FROM companies
WHERE is_active = 1
AND NOT EXISTS (
    SELECT 1 FROM users WHERE role = 'analyst'
);

SELECT * 
FROM stock_prices 
WHERE company_id IN (
    SELECT company_id 
    FROM companies 
    WHERE industry_id IN (
        SELECT industry_id FROM companies WHERE ceo = 'Bob Williams'
    )
    OR sector_id IN (
        SELECT sector_id FROM companies WHERE ceo = 'Bob Williams'
    )
);

SELECT 
  (SELECT COUNT(*) FROM users WHERE is_active = 1) AS active_users, 
  (SELECT COUNT(*) FROM companies WHERE is_active = 1) AS active_companies;
